using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using HttpClient.
/// Uses constructor injection — the SDK resolves DI services automatically.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all users from the API. Returns JSON array of user objects.")]
    public async Task<string> ListUsers(
        [Description("Maximum number of results to return (1-100)")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing users with limit {Limit}", limit);
        var response = await httpClient.GetStringAsync($"/users?_limit={limit}", cancellationToken);
        return response;
    }

    [McpServerTool, Description("Get a single user by their numeric ID.")]
    public async Task<string> GetUser(
        [Description("The user's numeric ID")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {UserId}", userId);
        var response = await httpClient.GetAsync($"/users/{userId}", cancellationToken);

        if (!response.IsSuccessStatusCode)
        {
            return $"Error: User {userId} not found (HTTP {(int)response.StatusCode})";
        }

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }

    [McpServerTool, Description("Search posts by user ID. Returns matching blog posts as JSON.")]
    public async Task<string> GetPostsByUser(
        [Description("The user ID to filter posts by")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching posts for user {UserId}", userId);
        var response = await httpClient.GetStringAsync($"/posts?userId={userId}", cancellationToken);
        return response;
    }

    [McpServerTool, Description("Create a new post. Returns the created post as JSON.")]
    public async Task<string> CreatePost(
        [Description("Title of the new post")] string title,
        [Description("Body content of the post")] string body,
        [Description("ID of the user creating the post")] int userId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating post for user {UserId}", userId);

        var payload = new { title, body, userId };
        var response = await httpClient.PostAsJsonAsync("/posts", payload, cancellationToken);
        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        return content;
    }
}

